package com.google.gson;
import com.google.gson.internal.NonNullElementWrapperList;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Iterator;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;
import java.util.ArrayList;

class JsonArrayTest {

  private JsonArray jsonArray;

  @BeforeEach
  void setUp() {
    jsonArray = new JsonArray();
  }

  @Test
  void testIsEmpty_whenElementsListIsEmpty_shouldReturnTrue() throws Exception {
    // Using reflection to ensure elements is empty
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    ArrayList<?> elements = (ArrayList<?>) elementsField.get(jsonArray);
    elements.clear();

    assertTrue(jsonArray.isEmpty());
  }

  @Test
  void testIsEmpty_whenElementsListHasElements_shouldReturnFalse() throws Exception {
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    @SuppressWarnings("unchecked")
    ArrayList<JsonElement> elements = (ArrayList<JsonElement>) elementsField.get(jsonArray);

    JsonElement mockElement = new JsonPrimitive("test");
    elements.add(mockElement);

    assertFalse(jsonArray.isEmpty());
  }
}
